const body = $input.first().json.body;
const day = body.day ?? 1;
const closeItEnabled = body.closeItEnabled !== false;
const leads = body.leads ?? [];
const threads = body.threads ?? {};

const existingNames = leads.map(l => l.name.toLowerCase());
const existingEmails = leads.map(l => l.email.toLowerCase());
const existingCompanies = leads.map(l => (l.company ?? '').toLowerCase());

const ACTIVE_STATUSES = ['Contacted', 'Awaiting Reply', 'Replied', 'Discovery Booked'];
const activeLeads = leads.filter(l => ACTIVE_STATUSES.includes(l.status));

// Random reply selection — probability by intent, no cadence gate
// Lead only replies if last message in thread is NOT from lead (it's their turn)
const replyingLeads = activeLeads.filter(lead => {
  if (lead.status === 'Discovery Booked') return false;
  // Ball is with user — lead must NOT generate AI replies until user responds
  if (lead.status === 'Replied') return false;
  const thread = threads[lead.id] ?? [];
  if (thread.length === 0) return false;
  const lastMsg = thread[thread.length - 1];
  if (lastMsg.from === 'lead') return false; // last message was from lead, not their turn
  const prob = lead.intentSignal === 'high' ? 0.70 : lead.intentSignal === 'medium' ? 0.40 : 0.15;
  return Math.random() < prob;
});

// ── Follow-up engine ────────────────────────────────────────────────────────
// All leads excluded from follow-up today:
//   - replying today (they'll be in replyingLeads)
//   - last thread message < 2 days old (conversation is still active)
//   - closed / nurture / no thread yet

const replyingLeadIds = new Set(replyingLeads.map(l => l.id));

const followUpCandidates = closeItEnabled ? leads.filter(lead => {
  if (['Closed Won', 'Closed Lost', 'Nurture', 'New'].includes(lead.status)) return false;
  if (replyingLeadIds.has(lead.id)) return false;
  if ((lead.agentFollowUpCount ?? 0) >= 6) return false; // hard cap
  const thread = threads[lead.id] ?? [];
  if (thread.length === 0) return false; // no messages yet
  const lastMsg = thread[thread.length - 1];
  return (day - (lastMsg.day ?? 0)) >= 2;
}) : [];

// PRE-DISCOVERY: hasn't booked a call yet → agent email summarising thread + booking pitch
const preDiscoveryFollowUps = followUpCandidates.filter(l => l.status !== 'Discovery Booked');

// POST-DISCOVERY: call is booked → check who spoke last
const postDiscoveryLeads = followUpCandidates.filter(l => l.status === 'Discovery Booked');
const postDiscoveryNudgeLead = postDiscoveryLeads.filter(lead => {
  const thread = threads[lead.id] ?? [];
  const lastMsg = thread[thread.length - 1];
  return lastMsg && (lastMsg.from === 'user' || lastMsg.from === 'agent');
});
const postDiscoveryNudgeUser = postDiscoveryLeads.filter(lead => {
  const thread = threads[lead.id] ?? [];
  const lastMsg = thread[thread.length - 1];
  return lastMsg && lastMsg.from === 'lead';
});

// Keep for backward compat with Assemble Response reads
const postUserReplyNudges = [];
const momNudgeLeads = [];

return [{ json: { day, closeItEnabled, leads, threads, existingNames, existingEmails, existingCompanies, activeLeads, replyingLeads, preDiscoveryFollowUps, postDiscoveryNudgeLead, postDiscoveryNudgeUser, postUserReplyNudges, momNudgeLeads } }];

const state = $('Parse State').first().json;
const existingNames = (state.existingNames ?? []).join(', ');
const count = Math.floor(Math.random() * 4) + 2;

const userContent = `Generate ${count} unique B2B leads. Each object must have:\n- name: full name (realistic, diverse)\n- company: company name\n- industry: one of [Sales Consulting, SaaS/Analytics, E-commerce, Legal Services, Manufacturing, Health Tech, Digital Marketing, Fintech, Real Estate, HR Tech]\n- email: professional email\n- startType: "cold" (70%) or "warm" (30%)\n- intentSignal: "high" (30%), "medium" (40%), or "low" (30%)\n- replyFrequencyDays: integer 2-6\n- inboundMessage: if warm, a realistic first message to CloseIt (an AI CRM automation platform). If cold, null.\n\nExclude these existing names: ${existingNames}\n\nReturn ONLY the JSON array.`;

const body = JSON.stringify({
  model: "gpt-4o-mini",
  temperature: 0.9,
  max_tokens: 1200,
  messages: [
    { role: "system", content: "You generate realistic B2B leads for a CRM automation demo. Return ONLY a valid JSON array, no markdown, no explanation." },
    { role: "user", content: userContent }
  ]
});

return [{ json: { body } }];

const state = $('Parse State').first().json;
const day = state.day;
const existingNames = state.existingNames ?? [];
const existingEmails = state.existingEmails ?? [];
const existingCompanies = state.existingCompanies ?? [];

const raw = $input.first().json.choices?.[0]?.message?.content ?? '[]';
let generated = [];
try {
  const cleaned = raw.replace(/```json|```/g, '').trim();
  const parsed = JSON.parse(cleaned);
  generated = Array.isArray(parsed) ? parsed : [];
} catch { generated = []; }

const newLeads = generated
  .filter(l => {
    if (!l.name) return false;
    if (existingNames.includes(l.name.toLowerCase())) return false;
    if (existingEmails.includes((l.email ?? '').toLowerCase())) return false;
    if (l.company && existingCompanies.includes(l.company.toLowerCase())) return false;
    return true;
  })
  .map((l, i) => ({
    id: `n8n_lead_d${day}_${i}`,
    name: l.name,
    company: l.company ?? 'Unknown Co',
    industry: l.industry ?? 'General',
    email: l.email ?? `${l.name.toLowerCase().replace(/\s+/g,'.')}@${(l.company ?? 'co').toLowerCase().replace(/[^a-z]/g,'')}.com`,
    startType: l.startType ?? 'cold',
    intentSignal: l.intentSignal ?? 'medium',
    replyFrequencyDays: Number(l.replyFrequencyDays) || 3,
    inboundMessage: l.inboundMessage ?? null,
    score: 6, scoreDelta: 0, status: 'New',
    registeredOnDay: day,
    lastReplyDay: null, lastUserReplyDay: null,
    discoveryCallDay: null,
    agentFollowUpCount: 0, lastAgentFollowUpDay: null,
    agentNudgeCount: 0, lastAgentNudgeDay: null
  }));

return [{ json: { newLeads, day } }];

const state = $('Parse State').first().json;
const replyingLeads = state.replyingLeads ?? [];
const threads = state.threads ?? {};

if (replyingLeads.length === 0) {
  return [{ json: { body: JSON.stringify({ model: 'gpt-4o-mini', max_tokens: 10, messages: [{ role: 'user', content: 'Reply with empty JSON array: []' }] }) } }];
}

const leadsPayload = replyingLeads.map(l => {
  const thread = threads[l.id] ?? [];
  const leadMsgCount = thread.filter(m => m.from === 'lead').length;
  return {
    id: l.id,
    name: l.name,
    company: l.company,
    industry: l.industry,
    intentSignal: l.intentSignal,
    startType: l.startType,
    leadMsgCount,  // how many times this lead has already replied
    thread: thread.map(m => `[${m.from.toUpperCase()}] ${m.body}`).join('\n\n')
  };
});

const body = JSON.stringify({
  model: "gpt-4o-mini",
  temperature: 0.85,
  max_tokens: 2000,
  messages: [
    {
      role: "system",
      content: `You simulate realistic B2B sales email conversations for a CRM demo. Conversations must feel natural and progressive — DO NOT rush to booking a call.

Reply guidelines based on leadMsgCount (how many times the lead has replied so far):
- leadMsgCount 0 (first reply ever): Show mild curiosity. Ask 1-2 clarifying questions about the product. No commitment. containsBookingSignal=false.
- leadMsgCount 1: Share a bit more context (one pain point or rough budget range). Still evaluating. containsBookingSignal=false.
- leadMsgCount 2 (warm leads only): Can express stronger interest and agree to a demo/call. containsBookingSignal may be true for warm+high intent leads.
- leadMsgCount 3+ (any lead): Can agree to a discovery call if intent is medium/high. containsBookingSignal may be true.
- Low intent leads: Always one step more hesitant than medium/high. Even at leadMsgCount 3, low intent leads ask one more question rather than booking.
- Keep replies under 80 words. Sound like a real busy professional, not a marketing bot.
- Return ONLY valid JSON array, no markdown.`
    },
    {
      role: "user",
      content: `Generate the next email reply for each lead.\n\nLeads:\n${JSON.stringify(leadsPayload)}\n\nReturn JSON array: [{ "leadId": "...", "replyText": "...", "containsBookingSignal": true/false }]`
    }
  ]
});

return [{ json: { body } }];

const state = $('Parse State').first().json;
const preDiscovery = state.preDiscoveryFollowUps ?? [];
const postNudgeLead = state.postDiscoveryNudgeLead ?? [];
const threads = state.threads ?? {};
const day = state.day;

const needsAIEmail = [...preDiscovery, ...postNudgeLead];

if (needsAIEmail.length === 0) {
  return [{ json: { body: JSON.stringify({ model: 'gpt-4o-mini', max_tokens: 10, messages: [{ role: 'user', content: 'Reply with empty JSON array: []' }] }) } }];
}

const payload = needsAIEmail.map(l => {
  const thread = threads[l.id] ?? [];
  const lastMsg = thread[thread.length - 1];
  const isPostDiscovery = l.status === 'Discovery Booked';
  const followUpNum = (l.agentFollowUpCount ?? 0) + 1;
  // Extract what the lead has shared: budget, timeline, pain points from thread text
  const leadMsgs = thread.filter(m => m.from === 'lead').map(m => m.body).join(' | ');
  return {
    id: l.id,
    type: isPostDiscovery ? 'post_discovery' : 'pre_discovery',
    name: l.name,
    company: l.company,
    industry: l.industry,
    intentSignal: l.intentSignal,
    followUpNum,
    daysSinceLastMessage: day - (lastMsg?.day ?? 0),
    lastSender: lastMsg?.from ?? 'agent',
    leadSharedSoFar: leadMsgs || 'Nothing specific shared yet',
    thread: thread.map(m => `[${m.from.toUpperCase()}] ${m.body}`).join('\n\n')
  };
});

const body = JSON.stringify({
  model: 'gpt-4o-mini',
  temperature: 0.8,
  max_tokens: 3000,
  messages: [
    {
      role: 'system',
      content: `You are CloseIt, an AI sales assistant writing follow-up emails on behalf of a salesperson.

PRE-DISCOVERY follow-ups (type: "pre_discovery"):
- Read the thread carefully. Identify: what pain points the lead has mentioned, their industry, any budget/timeline hints.
- Open by referencing something SPECIFIC the lead said (shows you read their message).
- Briefly summarise your understanding of their business need in 1-2 sentences.
- Connect that need to a concrete outcome CloseIt delivers.
- End with a single clear ask: a 20-minute discovery call with a proposed day/time.
- followUpNum 1: warm and curious tone. followUpNum 2+: more direct, create mild urgency.
- Under 90 words. Sound human, not scripted.

POST-DISCOVERY follow-ups (type: "post_discovery"):
- Discovery call is booked or was discussed. The lead has gone quiet.
- Reference the call/discussion and one specific thing agreed or mentioned.
- Ask a simple, easy-to-answer question to re-engage.
- Under 70 words.

Return ONLY a valid JSON array, no markdown.`
    },
    {
      role: 'user',
      content: `Write follow-up emails for these leads.\n\nLeads:\n${JSON.stringify(payload)}\n\nReturn JSON array: [{ "leadId": "...", "type": "pre_discovery" or "post_discovery", "emailBody": "..." }]`
    }
  ]
});

return [{ json: { body } }];

const state = $('Parse State').first().json;
const { day, leads, threads, replyingLeads, preDiscoveryFollowUps, postDiscoveryNudgeLead, postDiscoveryNudgeUser } = state;

function safeContent(nodeName) {
  try {
    const items = $(nodeName).all();
    return items.length > 0 ? (items[0].json?.choices?.[0]?.message?.content ?? '[]') : '[]';
  } catch (_) { return '[]'; }
}

function safeParse(raw) {
  try {
    const cleaned = raw.replace(/```json|```/g, '').trim();
    const result = JSON.parse(cleaned);
    return Array.isArray(result) ? result : [];
  } catch (_) { return []; }
}

const replies = safeParse(safeContent('OpenAI: Generate Lead Replies'));
const followUpEmails = safeParse(safeContent('OpenAI: Generate Follow-ups & Nudges'));

let newLeads = [];
try {
  const items = $('Process New Leads').all();
  newLeads = items.length > 0 ? (items[0].json?.newLeads ?? []) : [];
} catch (_) { newLeads = []; }

const threadMessages = [], statusUpdates = [], agentActions = [], notifications = [], tasks = [], leadUpdates = [];

// 1. New lead arrivals
for (const l of newLeads) {
  notifications.push({ type: 'lead_arrived', message: `New lead: ${l.name} from ${l.company} (${l.startType === 'warm' ? 'warm inbound' : 'cold outreach'})` });
  if (l.startType === 'warm' && l.inboundMessage) {
    threadMessages.push({ leadId: l.id, from: 'lead', body: l.inboundMessage, day });
    statusUpdates.push({ leadId: l.id, status: 'Replied' });
  }
}

// 2. AI-simulated lead replies
for (const [idx, r] of replies.entries()) {
  // Exact ID match first; fall back to positional (GPT sometimes modifies the leadId string)
  let lead = (replyingLeads ?? []).find(l => l.id === r.leadId);
  if (!lead && idx < (replyingLeads ?? []).length) lead = (replyingLeads ?? [])[idx];
  if (!lead || !r.replyText) continue;
  const leadId = lead.id; // always use canonical ID, never trust GPT's r.leadId
  threadMessages.push({ leadId, from: 'lead', body: r.replyText, day });
  // Gate: require minimum back-and-forth before booking — warm leads need 2 lead msgs, cold need 3
  const existingLeadMsgs = ((threads ?? {})[leadId] ?? []).filter(m => m.from === 'lead').length;
  const minMsgsToBook = lead.startType === 'warm' ? 2 : 3;
  const canBook = r.containsBookingSignal && existingLeadMsgs >= minMsgsToBook;
  if (canBook && lead.status !== 'Discovery Booked') {
    const callDay = day + 1;
    statusUpdates.push({ leadId, status: 'Discovery Booked', discoveryCallDay: callDay });
    agentActions.push({ id: `act_${day}_disc_${leadId}`, day, type: 'discovery_call_booked', leadId, leadName: lead.name, summary: `Discovery call booked with ${lead.name} (${lead.company}) — Day ${callDay}`, actor: 'ai', detail: { callDay }, timestamp: new Date().toISOString() });
    tasks.push({ leadId, leadName: lead.name, company: lead.company, callDay });
    notifications.push({ type: 'call_booked', message: `Discovery call booked with ${lead.name} (${lead.company})` });
  } else {
    statusUpdates.push({ leadId, status: 'Replied' });
  }
  agentActions.push({ id: `act_${day}_reply_${leadId}`, day, type: 'lead_replied', leadId, leadName: lead.name, summary: `${lead.name} replied`, actor: 'lead', detail: { body: r.replyText }, timestamp: new Date().toISOString() });
  // Alert the user — they need to respond via the compose box
  notifications.push({ type: 'lead_replied', message: `${lead.name} (${lead.company}) replied — open their thread and respond` });
}

// 3. Follow-up emails (pre-discovery + post-discovery nudge-lead)
const allFollowUpEmails = followUpEmails;
const allFollowUpLeads = [...(preDiscoveryFollowUps ?? []), ...(postDiscoveryNudgeLead ?? [])];

for (const [idx, fu] of allFollowUpEmails.entries()) {
  let lead = allFollowUpLeads.find(l => l.id === fu.leadId);
  if (!lead && idx < allFollowUpLeads.length) lead = allFollowUpLeads[idx];
  if (!lead || !fu.emailBody) continue;
  const leadId = lead.id;
  threadMessages.push({ leadId, from: 'agent', body: fu.emailBody, day });
  const fuNum = (lead.agentFollowUpCount ?? 0) + 1;
  const label = fu.type === 'post_discovery'
    ? `Post-discovery follow-up #${fuNum} sent to ${lead.name}`
    : `Pre-discovery follow-up #${fuNum} sent to ${lead.name} — booking pitch`;
  agentActions.push({ id: `act_${day}_fu_${leadId}`, day, type: 'initial_email_sent', leadId, leadName: lead.name, summary: label, actor: 'ai', detail: { body: fu.emailBody, followUpNum: fuNum, type: fu.type }, timestamp: new Date().toISOString() });
  leadUpdates.push({ leadId, agentFollowUpCount: fuNum, lastAgentFollowUpDay: day });
  if (fu.type === 'pre_discovery') statusUpdates.push({ leadId, status: 'Awaiting Reply' });
}

// 4. Post-discovery nudge to USER (lead spoke last, user needs to respond)
for (const lead of (postDiscoveryNudgeUser ?? [])) {
  notifications.push({ type: 'lead_replied', message: `${lead.name} (${lead.company}) is waiting — they replied to your discovery call thread. Respond now.` });
  agentActions.push({ id: `act_${day}_nudge_user_${lead.id}`, day, type: 'initial_email_sent', leadId: lead.id, leadName: lead.name, summary: `User nudged: ${lead.name} replied post-discovery, awaiting your response`, actor: 'system', detail: { type: 'post_discovery_nudge_user' }, timestamp: new Date().toISOString() });
}

// 5. Score all leads
const POS = ['interested','sounds good',"let's",'schedule','book','call','demo','yes','definitely','great','perfect','keen','forward','available','when can','happy to'];
const NEG = ['not interested','no thanks','unsubscribe','remove','stop','busy','later','maybe next','not right now'];
const scoreUpdates = [...(leads ?? []), ...newLeads]
  .filter(l => !['Closed Won','Closed Lost','Nurture'].includes(l.status))
  .map(lead => {
    const thread = (threads ?? {})[lead.id] ?? [];
    const leadMsgs = thread.filter(m => m.from === 'lead');
    const lastLeadMsg = leadMsgs[leadMsgs.length - 1];
    const allText = leadMsgs.map(m => m.body.toLowerCase()).join(' ');
    const posHits = POS.filter(k => allText.includes(k)).length;
    const negHits = NEG.filter(k => allText.includes(k)).length;
    const intentScore = Math.min(4, Math.max(0, posHits - negHits * 2));
    const daysSince = lastLeadMsg ? (day - lastLeadMsg.day) : day;
    const recencyPenalty = Math.max(-3, -Math.floor(daysSince / lead.replyFrequencyDays));
    const replyCount = leadMsgs.length;
    const expectedReplies = Math.max(1, Math.floor(day / lead.replyFrequencyDays));
    const freqBonus = replyCount >= expectedReplies ? Math.min(2, replyCount - expectedReplies + 1) : 0;
    const callBonus = lead.status === 'Discovery Booked' ? 2 : 0;
    const newScore = Math.min(10, Math.max(0, 6 + intentScore + recencyPenalty + freqBonus + callBonus));
    const delta = newScore - (lead.score ?? 6);
    if (newScore < 4 && (lead.score ?? 6) >= 4) notifications.push({ type: 'score_critical', message: `${lead.name}'s score dropped to ${newScore} — needs attention` });
    return { leadId: lead.id, score: newScore, delta };
  });

// Deduplicate statusUpdates: keep highest-priority status per lead so replies/bookings aren't overwritten by follow-ups
const STATUS_PRIORITY = { 'Discovery Booked': 5, 'Replied': 4, 'Awaiting Reply': 3, 'Contacted': 2, 'New': 1 };
const statusMapFinal = {};
for (const u of statusUpdates) {
  const existing = statusMapFinal[u.leadId];
  if (!existing || (STATUS_PRIORITY[u.status] ?? 0) > (STATUS_PRIORITY[existing.status] ?? 0)) {
    statusMapFinal[u.leadId] = u;
  }
}
const dedupedStatusUpdates = Object.values(statusMapFinal);

return [{ json: { newLeads, threadMessages, scoreUpdates, statusUpdates: dedupedStatusUpdates, leadUpdates, agentActions, notifications, tasks } }];

const newLeads = $('Assemble Response').first().json.newLeads ?? [];

const leadsPayload = newLeads.map(l => ({
  id: l.id,
  name: l.name,
  company: l.company,
  industry: l.industry,
  startType: l.startType,
  inboundMessage: l.inboundMessage ?? null
}));

const userContent = `Write initial contact emails for these leads. Cold leads: introduce CloseIt (an AI CRM automation platform), mention their specific industry, ask one hook question. Warm leads: acknowledge their inbound message and ask 4 discovery questions (budget, timeline, current tooling, main pain point).\n\nLeads:\n${JSON.stringify(leadsPayload)}\n\nReturn a JSON array: [{ "leadId": "...", "emailBody": "..." }]`;

const body = JSON.stringify({
  model: "gpt-4o-mini",
  temperature: 0.85,
  max_tokens: 2500,
  messages: [
    {
      role: "system",
      content: "You are CloseIt, an AI CRM automation platform. Write the first outreach email to new B2B leads. Sound like a knowledgeable human — not a bot. Emails under 80 words. Return ONLY a valid JSON array, no markdown, no explanation."
    },
    {
      role: "user",
      content: userContent
    }
  ]
});

return [{ json: { body, newLeads } }];

const assembled = $('Assemble Response').first().json;
const day = $('Parse State').first().json.day;

let initialEmails = [];
try {
  const raw = $('OpenAI: Initial Emails').first().json.choices?.[0]?.message?.content ?? '[]';
  const parsed = JSON.parse(raw.replace(/```json|```/g,'').trim());
  initialEmails = Array.isArray(parsed) ? parsed : [];
} catch (_) { initialEmails = []; }

const extraMessages = [];
const extraActions = [];
const extraStatusUpdates = [];

for (const ie of initialEmails) {
  const lead = (assembled.newLeads ?? []).find(l => l.id === ie.leadId);
  if (!lead || !ie.emailBody) continue;

  extraMessages.push({ leadId: ie.leadId, from: 'agent', body: ie.emailBody, day });

  // Warm leads already have status='Replied' from their inbound message — don't downgrade to 'Contacted'
  if (lead.startType !== 'warm') {
    extraStatusUpdates.push({ leadId: ie.leadId, status: 'Contacted' });
  }

  extraActions.push({
    id: `act_${day}_init_${ie.leadId}`,
    day,
    type: 'initial_email_sent',
    leadId: ie.leadId,
    leadName: lead.name,
    summary: `Initial ${lead.startType === 'warm' ? 'warm response' : 'cold outreach'} sent to ${lead.name} (${lead.company})`,
    actor: 'ai',
    detail: { body: ie.emailBody, startType: lead.startType },
    timestamp: new Date().toISOString()
  });
}

const finalResult = {
  newLeads: assembled.newLeads ?? [],
  threadMessages: [...(assembled.threadMessages ?? []), ...extraMessages],
  scoreUpdates: assembled.scoreUpdates ?? [],
  statusUpdates: [...(assembled.statusUpdates ?? []), ...extraStatusUpdates],
  leadUpdates: assembled.leadUpdates ?? [],
  agentActions: [...(assembled.agentActions ?? []), ...extraActions],
  notifications: assembled.notifications ?? [],
  tasks: assembled.tasks ?? []
};

return [{ json: finalResult }];

// Prepare flat rows for Activity Log
const result = $('Merge Initial Emails').first().json;
const day = $('Parse State').first().json.day;
const rows = [];

for (const msg of result.threadMessages ?? []) {
  rows.push({ day, leadId: msg.leadId, action_type: `message_${msg.from}`, actor: msg.from, summary: msg.body.substring(0,100), detail_json: JSON.stringify(msg), timestamp: new Date().toISOString() });
}
for (const a of result.agentActions ?? []) {
  rows.push({ day, leadId: a.leadId, action_type: a.type, actor: a.actor, summary: a.summary, detail_json: JSON.stringify(a.detail), timestamp: a.timestamp });
}

return rows.length ? rows.map(r => ({ json: r })) : [{ json: { day, action_type: 'no_op', actor: 'system', summary: 'No actions this day', timestamp: new Date().toISOString() } }];
